'use strict';
const fs = require('fs');
const path = require('path');
const { AppError } = require('../lib/errors.js');
const { allCustomers } = require('../core/customers.js');
const { toCSV, toJSON } = require('../lib/format.js');
const { outputDir } = require('../config.js');

function exportCustomers(args) {
  const fmtIndex = args.indexOf('--format');
  const format = fmtIndex !== -1 ? args[fmtIndex + 1] : 'csv';

  if (format !== 'csv' && format !== 'json') {
    throw new AppError(`unsupported format: ${format}`, 2);
  }

  const customers = allCustomers();

  const serialized = format === 'csv'
    ? toCSV(customers, ['id', 'name', 'email'])
    : toJSON(customers);

  const ext = format;
  const dir = outputDir;
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(path.join(dir, `customers.${ext}`), serialized);

  return [`exported to ${dir}/customers.${ext}`];
}

module.exports = { exportCustomers };

